1	/**
2	 * Mixer panel with horizontal channel strips.
3	 * Reads track state from Zustand store.
4	 * Metering is driven by canvas rAF loop (NFR-13) -- currently static
5	 * until the audio engine is wired to real AnalyserNode data.
6	 */
7	
8	import { useCallback } from "react";
9	import { useDawStore } from "@state/store";
10	import { ChannelStrip } from "./ChannelStrip";
11	import { MasterStrip } from "./MasterStrip";
12	import styles from "./MixerPanel.module.css";
13	
14	export function MixerPanel(): React.JSX.Element {
15	  const tracks = useDawStore((s) => s.tracks);
16	  const masterVolume = useDawStore((s) => s.masterVolume);
17	  const updateTrack = useDawStore((s) => s.updateTrack);
18	  const setMasterVolume = useDawStore((s) => s.setMasterVolume);
19	
20	  const handleVolumeChange = useCallback(
21	    (trackId: string, volume: number) => {
22	      updateTrack(trackId, { volume });
23	    },
24	    [updateTrack],
25	  );
26	
27	  const handlePanChange = useCallback(
28	    (trackId: string, pan: number) => {
29	      updateTrack(trackId, { pan });
30	    },
31	    [updateTrack],
32	  );
33	
34	  const handleMuteToggle = useCallback(
35	    (trackId: string) => {
36	      const track = useDawStore.getState().tracks.find((t) => t.id === trackId);
37	      if (track) updateTrack(trackId, { muted: !track.muted });
38	    },
39	    [updateTrack],
40	  );
41	
42	  const handleSoloToggle = useCallback(
43	    (trackId: string) => {
44	      const track = useDawStore.getState().tracks.find((t) => t.id === trackId);
45	      if (track) updateTrack(trackId, { solo: !track.solo });
46	    },
47	    [updateTrack],
48	  );
49	
50	  return (
51	    <section data-testid="mixer-panel" className={styles["mixer"]}>
52	      {tracks.map((track) => (
53	        <ChannelStrip
54	          key={track.id}
55	          trackId={track.id}
56	          name={track.name}
57	          color={track.color}
58	          volume={track.volume}
59	          pan={track.pan}
60	          muted={track.muted}
61	          solo={track.solo}
62	          meterLevel={0}
63	          meterPeak={0}
64	          clipping={false}
65	          onVolumeChange={handleVolumeChange}
66	          onPanChange={handlePanChange}
67	          onMuteToggle={handleMuteToggle}
68	          onSoloToggle={handleSoloToggle}
69	        />
70	      ))}
71	      <MasterStrip
72	        volume={masterVolume}
73	        meterLevel={0}
74	        meterPeak={0}
75	        clipping={false}
76	        onVolumeChange={setMasterVolume}
77	      />
78	    </section>
79	  );
80	}
