1	/**
2	 * Individual channel strip for the mixer panel.
3	 * Fader, pan knob, mute/solo buttons, VU meter, track name.
4	 */
5	
6	import { useCallback } from "react";
7	import { Fader } from "@ui/controls/Fader";
8	import { RotaryKnob } from "@ui/controls/RotaryKnob";
9	import { VuMeter } from "@ui/controls/VuMeter";
10	import { volumeToDb } from "./format";
11	import styles from "./MixerPanel.module.css";
12	
13	type ChannelStripProps = {
14	  trackId: string;
15	  name: string;
16	  color: string;
17	  volume: number;
18	  pan: number;
19	  muted: boolean;
20	  solo: boolean;
21	  meterLevel: number;
22	  meterPeak: number;
23	  clipping: boolean;
24	  onVolumeChange: (trackId: string, volume: number) => void;
25	  onPanChange: (trackId: string, pan: number) => void;
26	  onMuteToggle: (trackId: string) => void;
27	  onSoloToggle: (trackId: string) => void;
28	};
29	
30	export function ChannelStrip({
31	  trackId,
32	  name,
33	  color,
34	  volume,
35	  pan,
36	  muted,
37	  solo,
38	  meterLevel,
39	  meterPeak,
40	  clipping,
41	  onVolumeChange,
42	  onPanChange,
43	  onMuteToggle,
44	  onSoloToggle,
45	}: ChannelStripProps): React.JSX.Element {
46	  const handleVolume = useCallback(
47	    (v: number) => {
48	      onVolumeChange(trackId, v / 100);
49	    },
50	    [trackId, onVolumeChange],
51	  );
52	  const handlePan = useCallback(
53	    (v: number) => {
54	      onPanChange(trackId, v / 100);
55	    },
56	    [trackId, onPanChange],
57	  );
58	  const handleMute = useCallback(() => {
59	    onMuteToggle(trackId);
60	  }, [trackId, onMuteToggle]);
61	  const handleSolo = useCallback(() => {
62	    onSoloToggle(trackId);
63	  }, [trackId, onSoloToggle]);
64	
65	  return (
66	    <div className={styles["strip"]} data-testid={`channel-strip-${trackId}`}>
67	      <div
68	        style={{
69	          width: "100%",
70	          height: 3,
71	          backgroundColor: color,
72	        }}
73	      />
74	      <div className={styles["name"]}>{name}</div>
75	
76	      <RotaryKnob
77	        value={Math.round(pan * 100)}
78	        min={-100}
79	        max={100}
80	        step={1}
81	        onChange={handlePan}
82	        label="PAN"
83	        size={32}
84	      />
85	
86	      <div className={styles["meter-fader-row"]}>
87	        <VuMeter
88	          level={meterLevel}
89	          peak={meterPeak}
90	          clip={clipping}
91	          width={8}
92	          height={96}
93	        />
94	        <Fader
95	          value={Math.round(volume * 100)}
96	          min={0}
97	          max={200}
98	          step={1}
99	          onChange={handleVolume}
100	          label=""
101	          height={96}
102	        />
103	      </div>
104	
105	      <div className={styles["db-label"]}>{volumeToDb(volume)}</div>
106	
107	      <div className={styles["controls-row"]}>
108	        <button
109	          className={
110	            muted ? (styles["btn-mute-active"] ?? "") : (styles["btn"] ?? "")
111	          }
112	          onClick={handleMute}
113	          aria-label={muted ? "Unmute" : "Mute"}
114	          type="button"
115	        >
116	          M
117	        </button>
118	        <button
119	          className={
120	            solo ? (styles["btn-solo-active"] ?? "") : (styles["btn"] ?? "")
121	          }
122	          onClick={handleSolo}
123	          aria-label={solo ? "Unsolo" : "Solo"}
124	          type="button"
125	        >
126	          S
127	        </button>
128	      </div>
129	    </div>
130	  );
131	}
