1	/**
2	 * Offline synth renderer: renders MIDI note events to stereo audio
3	 * using the synth DSP functions directly (no AudioWorklet dependency).
4	 *
5	 * This mirrors the SynthProcessor logic but runs synchronously,
6	 * producing Float32Arrays suitable for use as AudioBufferSourceNodes
7	 * in the offline bounce context.
8	 */
9	
10	import type { MIDINoteEvent } from "@state/track/types";
11	import type { SynthParameterMap } from "@audio/synth/synth-types";
12	import { midiToFreq } from "@audio/synth/synth-types";
13	import { createPolyBLEPOsc } from "@audio/synth/dsp/polyblep";
14	import { createADSREnvelope, type ADSRParams } from "@audio/synth/dsp/adsr";
15	import {
16	  computeBiquadCoeffs,
17	  createBiquadFilter,
18	} from "@audio/synth/dsp/biquad-coeffs";
19	import { createLFO } from "@audio/synth/dsp/lfo";
20	
21	const MAX_VOICES = 16;
22	
23	type OfflineVoice = {
24	  active: boolean;
25	  releasing: boolean;
26	  note: number;
27	  osc1: ReturnType<typeof createPolyBLEPOsc>;
28	  osc2: ReturnType<typeof createPolyBLEPOsc>;
29	  ampEnv: ReturnType<typeof createADSREnvelope>;
30	  filterEnv: ReturnType<typeof createADSREnvelope>;
31	  filter: ReturnType<typeof createBiquadFilter>;
32	  targetFreq: number;
33	  currentFreq: number;
34	  velocity: number;
35	};
36	
37	function createOfflineVoice(): OfflineVoice {
38	  return {
39	    active: false,
40	    releasing: false,
41	    note: -1,
42	    osc1: createPolyBLEPOsc("saw"),
43	    osc2: createPolyBLEPOsc("saw"),
44	    ampEnv: createADSREnvelope(),
45	    filterEnv: createADSREnvelope(),
46	    filter: createBiquadFilter("lowpass"),
47	    targetFreq: 440,
48	    currentFreq: 440,
49	    velocity: 0,
50	  };
51	}
52	
53	type NoteEvent = {
54	  sample: number;
55	  type: "on" | "off";
56	  note: number;
57	  velocity: number;
58	};
59	
60	export type RenderedAudio = {
61	  readonly left: Float32Array;
62	  readonly right: Float32Array;
63	};
64	
65	/**
66	 * Render MIDI note events to stereo audio using synth DSP.
67	 * @param notes - MIDI note events (startTime relative to clip start)
68	 * @param duration - Total duration to render in seconds
69	 * @param sampleRate - Sample rate
70	 * @param params - Synth parameter snapshot
71	 */
72	export function renderMidiClipToAudio(
73	  notes: readonly MIDINoteEvent[],
74	  duration: number,
75	  sampleRate: number,
76	  params: SynthParameterMap,
77	): RenderedAudio {
78	  const totalSamples = Math.ceil(duration * sampleRate);
79	  const left = new Float32Array(totalSamples);
80	  const right = new Float32Array(totalSamples);
81	
82	  if (notes.length === 0) return { left, right };
83	
84	  // Build sorted event list (note-ons and note-offs)
85	  const events: NoteEvent[] = [];
86	  for (const note of notes) {
87	    const onSample = Math.floor(note.startTime * sampleRate);
88	    const offSample = Math.floor((note.startTime + note.duration) * sampleRate);
89	    events.push({
90	      sample: onSample,
91	      type: "on",
92	      note: note.pitch,
93	      velocity: note.velocity,
94	    });
95	    events.push({
96	      sample: offSample,
97	      type: "off",
98	      note: note.pitch,
99	      velocity: 0,
100	    });
101	  }
102	  events.sort((a, b) => a.sample - b.sample || (a.type === "off" ? -1 : 1));
103	
104	  // Pre-allocate voices
105	  const voices: OfflineVoice[] = Array.from({ length: MAX_VOICES }, () =>
106	    createOfflineVoice(),
107	  );
108	
109	  // LFOs not yet wired to modulation targets — created but not processed.
110	  // TODO: Wire LFO to pitch/filter/amp modulation to match SynthProcessor.
111	  void createLFO(params.lfo1Shape);
112	  void createLFO(params.lfo2Shape);
113	
114	  // ADSR params (pre-allocated)
115	  const ampParams: ADSRParams = {
116	    attack: params.ampAttack,
117	    decay: params.ampDecay,
118	    sustain: params.ampSustain,
119	    release: params.ampRelease,
120	  };
121	  const filterParams: ADSRParams = {
122	    attack: params.filterAttack,
123	    decay: params.filterDecay,
124	    sustain: params.filterSustain,
125	    release: params.filterRelease,
126	  };
127	
128	  // Pre-compute constants
129	  const osc1OctMul = Math.pow(2, params.osc1Octave);
130	  const osc1DetMul = Math.pow(2, params.osc1Detune / 1200);
131	  const osc2OctMul = Math.pow(2, params.osc2Octave);
132	  const osc2DetMul = Math.pow(2, params.osc2Detune / 1200);
133	
134	  let eventIdx = 0;
135	
136	  for (let s = 0; s < totalSamples; s++) {
137	    // Process events at this sample
138	    while (eventIdx < events.length) {
139	      const evt = events[eventIdx];
140	      if (!evt || evt.sample > s) break;
141	
142	      if (evt.type === "on") {
143	        allocateNoteOn(voices, evt.note, evt.velocity, params, sampleRate);
144	      } else {
145	        releaseNote(voices, evt.note);
146	      }
147	      eventIdx++;
148	    }
149	
150	    let mixL = 0;
151	    let mixR = 0;
152	
153	    for (let vi = 0; vi < MAX_VOICES; vi++) {
154	      const v = voices[vi];
155	      if (!v || !v.active) continue;
156	
157	      // Check if release finished
158	      if (v.ampEnv.stage === "idle" && v.releasing) {
159	        v.active = false;
160	        v.releasing = false;
161	        continue;
162	      }
163	
164	      // Pitch glide
165	      if (params.glideTime > 0 && v.currentFreq !== v.targetFreq) {
166	        const glideCoeff = 1 - Math.exp(-1 / (params.glideTime * sampleRate));
167	        v.currentFreq += glideCoeff * (v.targetFreq - v.currentFreq);
168	      } else {
169	        v.currentFreq = v.targetFreq;
170	      }
171	
172	      const baseFreq = v.currentFreq;
173	
174	      // Envelopes
175	      const filterEnvVal = v.filterEnv.process(filterParams, sampleRate);
176	      const ampLevel = v.ampEnv.process(ampParams, sampleRate);
177	
178	      // Oscillators
179	      const freq1 = baseFreq * osc1OctMul * osc1DetMul;
180	      const freq2 = baseFreq * osc2OctMul * osc2DetMul;
181	      const osc1Out = v.osc1.next(freq1, sampleRate) * params.osc1Level;
182	      const osc2Out = v.osc2.next(freq2, sampleRate) * params.osc2Level;
183	      let sample = osc1Out + osc2Out;
184	
185	      // Filter (recompute coefficients periodically for efficiency)
186	      if (s % 128 === 0) {
187	        const cutoffModSt = filterEnvVal * params.filterEnvDepth;
188	        const modulatedCutoff =
189	          params.filterCutoff * Math.pow(2, cutoffModSt / 12);
190	        const clampedCutoff = Math.min(
191	          Math.max(modulatedCutoff, 20),
192	          sampleRate / 2 - 100,
193	        );
194	        computeBiquadCoeffs(
195	          params.filterType,
196	          clampedCutoff,
197	          params.filterResonance,
198	          sampleRate,
199	          v.filter.coeffs,
200	        );
201	      }
202	
203	      sample = v.filter.process(sample);
204	
205	      // Velocity -> amplitude
206	      const velAmp = 0.5 + v.velocity * 0.5;
207	      sample *= ampLevel * velAmp * params.masterGain;
208	
209	      // Clamp to prevent overflow
210	      if (!isFinite(sample)) sample = 0;
211	
212	      mixL += sample;
213	      mixR += sample;
214	    }
215	
216	    left[s] = mixL;
217	    right[s] = mixR;
218	  }
219	
220	  return { left, right };
221	}
222	
223	/** Allocate a voice for a new note (oldest-steal if full) */
224	function allocateNoteOn(
225	  voices: OfflineVoice[],
226	  note: number,
227	  velocity: number,
228	  params: SynthParameterMap,
229	  sampleRate: number,
230	): void {
231	  // Find free voice
232	  let idx = -1;
233	  for (let i = 0; i < MAX_VOICES; i++) {
234	    if (voices[i]?.active !== true) {
235	      idx = i;
236	      break;
237	    }
238	  }
239	
240	  // Steal oldest releasing voice if no free voice
241	  if (idx === -1) {
242	    for (let i = 0; i < MAX_VOICES; i++) {
243	      if (voices[i]?.releasing === true) {
244	        idx = i;
245	        break;
246	      }
247	    }
248	  }
249	
250	  // Steal first voice as last resort
251	  if (idx === -1) idx = 0;
252	
253	  const v = voices[idx];
254	  if (!v) return;
255	
256	  const freq = midiToFreq(note);
257	  v.active = true;
258	  v.releasing = false;
259	  v.note = note;
260	  v.velocity = velocity / 127;
261	  v.targetFreq = freq;
262	  v.currentFreq = freq;
263	
264	  v.osc1.reset();
265	  v.osc2.reset();
266	  v.filter.reset();
267	  v.osc1.type = params.osc1Type;
268	  v.osc2.type = params.osc2Type;
269	  v.filter.type = params.filterType;
270	
271	  // Compute initial biquad coefficients so the filter doesn't produce silence
272	  // until the next s % 128 boundary in the render loop.
273	  computeBiquadCoeffs(
274	    params.filterType,
275	    Math.min(Math.max(params.filterCutoff, 20), sampleRate / 2 - 100),
276	    params.filterResonance,
277	    sampleRate,
278	    v.filter.coeffs,
279	  );
280	
281	  v.ampEnv.gate(false);
282	  v.filterEnv.gate(false);
283	}
284	
285	/** Release all voices playing this note */
286	function releaseNote(voices: OfflineVoice[], note: number): void {
287	  for (let i = 0; i < MAX_VOICES; i++) {
288	    const v = voices[i];
289	    if (v && v.active && !v.releasing && v.note === note) {
290	      v.releasing = true;
291	      v.ampEnv.release();
292	      v.filterEnv.release();
293	    }
294	  }
295	}
