1	/**
2	 * Creates a ParamResolver that maps automation lane targets to live AudioParams.
3	 * Bridges the automation scheduler to the mixer engine's real Web Audio nodes.
4	 */
5	
6	import type { MixerEngine } from "@audio/mixer";
7	import type { EffectsBridge } from "@audio/effects/effects-bridge";
8	import type { AutomationLane } from "./automation-types";
9	import type { ResolvedParam, ParamResolver } from "./automation-scheduler";
10	
11	/** Mixer fader range: 0 (silence) to 2 (boost) */
12	const VOLUME_RANGE = { min: 0, max: 2 } as const;
13	
14	/** Stereo pan range: -1 (left) to 1 (right) */
15	const PAN_RANGE = { min: -1, max: 1 } as const;
16	
17	export function createParamResolver(
18	  mixer: MixerEngine,
19	  _effectsBridge: EffectsBridge,
20	): ParamResolver {
21	  return (lane: AutomationLane): ResolvedParam | undefined => {
22	    const { target, trackId } = lane;
23	
24	    if (target.type === "mixer") {
25	      const strip = mixer.getStrip(trackId);
26	      if (!strip) return undefined;
27	
28	      switch (target.param) {
29	        case "volume":
30	          return { param: strip.faderGain.gain, range: VOLUME_RANGE };
31	        case "pan":
32	          return { param: strip.panner.pan, range: PAN_RANGE };
33	      }
34	    }
35	
36	    // Effect and synth params require AudioParam exposure from the effect/synth layer.
37	    // Currently effects use setParam() which doesn't expose raw AudioParams.
38	    // TODO: expose AudioParams from EffectInstance for sample-accurate automation.
39	    return undefined;
40	  };
41	}
