1	/** Convert linear gain 0..2 to dB display string */
2	export function volumeToDb(v: number): string {
3	  if (v <= 0) return "-inf";
4	  const db = 20 * Math.log10(v);
5	  return db >= 0 ? `+${db.toFixed(1)}` : db.toFixed(1);
6	}
