23	export const DEST_INDEX = {
24	  osc1Pitch: 0,
25	  osc2Pitch: 1,
26	  oscMix: 2,
27	  filterCutoff: 3,
28	  filterResonance: 4,
29	  ampLevel: 5,
30	  lfo1Rate: 6,
31	  lfo2Rate: 7,
32	} as const;
