1	/**
2	 * Bridge between effects Zustand store and Web Audio instances.
3	 * Subscribes to store changes, creates/disposes EffectInstances,
4	 * and wires them into the MixerEngine's insert chains.
5	 */
6	
7	import type { EffectInstance, EffectRegistry } from "./types";
8	import type { MixerEngine } from "@audio/mixer";
9	import { useEffectsStore } from "@state/effects";
10	import type { EffectSlotState } from "@state/effects";
11	
12	export type EffectsBridge = {
13	  /** Get a live audio instance by effect ID */
14	  getInstance(effectId: string): EffectInstance | undefined;
15	  /** Tear down all instances and unsubscribe */
16	  dispose(): void;
17	};
18	
19	export function createEffectsBridge(
20	  ctx: AudioContext,
21	  registry: EffectRegistry,
22	  mixer: MixerEngine,
23	): EffectsBridge {
24	  const instances = new Map<string, EffectInstance>();
25	  const effectTrackMap = new Map<string, string>();
26	
27	  function initInstance(
28	    trackId: string,
29	    slot: EffectSlotState,
30	  ): EffectInstance {
31	    const instance = registry.create(slot.typeId, ctx, slot.id);
32	    instances.set(slot.id, instance);
33	    effectTrackMap.set(slot.id, trackId);
34	
35	    for (const [key, value] of Object.entries(slot.params)) {
36	      instance.setParam(key, value);
37	    }
38	    instance.setBypassed(slot.bypassed);
39	    return instance;
40	  }
41	
42	  function syncSlot(trackId: string, slot: EffectSlotState): void {
43	    const existing = instances.get(slot.id);
44	    if (existing) {
45	      if (existing.typeId !== slot.typeId) {
46	        // Type swap: dispose old, create new, replace in-place to keep order
47	        existing.dispose();
48	        instances.delete(slot.id);
49	        const instance = initInstance(trackId, slot);
50	        mixer.replaceInsert(trackId, slot.id, instance.input, instance.output);
51	        return;
52	      }
53	
54	      // Sync params
55	      for (const [key, value] of Object.entries(slot.params)) {
56	        if (existing.getParam(key) !== value) {
57	          existing.setParam(key, value);
58	        }
59	      }
60	      // Sync bypass
61	      if (existing.bypassed !== slot.bypassed) {
62	        existing.setBypassed(slot.bypassed);
63	      }
64	      return;
65	    }
66	
67	    // Create new instance
68	    const instance = initInstance(trackId, slot);
69	    mixer.getOrCreateStrip(trackId);
70	    mixer.addInsert(trackId, slot.id, instance.input, instance.output);
71	  }
72	
73	  function removeInstance(effectId: string): void {
74	    const instance = instances.get(effectId);
75	    if (!instance) return;
76	
77	    const trackId = effectTrackMap.get(effectId);
78	    if (trackId !== undefined && trackId !== "") {
79	      mixer.removeInsert(trackId, effectId);
80	    }
81	
82	    instance.dispose();
83	    instances.delete(effectId);
84	    effectTrackMap.delete(effectId);
85	  }
86	
87	  function sync(): void {
88	    const state = useEffectsStore.getState();
89	    const activeIds = new Set<string>();
90	
91	    for (const [trackId, slots] of Object.entries(state.trackEffects)) {
92	      for (const slot of slots) {
93	        activeIds.add(slot.id);
94	        syncSlot(trackId, slot);
95	      }
96	    }
97	
98	    // Remove instances no longer in store
99	    for (const id of [...instances.keys()]) {
100	      if (!activeIds.has(id)) {
101	        removeInstance(id);
102	      }
103	    }
104	  }
105	
106	  // Initial sync
107	  sync();
108	
109	  // Subscribe to store changes
110	  const unsub = useEffectsStore.subscribe(sync);
111	
112	  return {
113	    getInstance(effectId) {
114	      return instances.get(effectId);
115	    },
116	    dispose() {
117	      unsub();
118	      for (const id of [...instances.keys()]) {
119	        removeInstance(id);
120	      }
121	    },
122	  };
123	}
124

/**
 * Automation scheduler for sample-accurate AudioParam playback.
 * Evaluates automation curves at exact breakpoints within scheduling windows
 * and applies values to AudioParams via setValueAtTime / linearRampToValueAtTime.
 *
 * Designed to be called from the look-ahead scheduler's advance callback.
 */

import type { AutomationLane, ParameterRange } from "./automation-types";
import {
  evaluateCurve,
  denormalize,
  findPointsInRange,
} from "./automation-curve";

/** Resolved parameter binding: the AudioParam to automate and its value range */
export type ResolvedParam = {
  /** The AudioParam or AudioParam-like object to schedule on */
  param: {
    value: number;
    setValueAtTime(value: number, time: number): void;
    linearRampToValueAtTime(value: number, time: number): void;
    cancelScheduledValues(startTime: number): void;
    cancelAndHoldAtTime?(startTime: number): void;
  };
  /** Parameter range for denormalization */
  range: ParameterRange;
};

/**
 * Resolver function: given a lane's trackId and target,
 * returns the AudioParam and its range, or undefined if unresolvable.
 */
export type ParamResolver = (lane: AutomationLane) => ResolvedParam | undefined;

export type AutomationScheduler = {
  /**
   * Schedule automation values for all lanes within a time window.
   * @param lanes - Active automation lanes to schedule
   * @param windowStart - Start of window in AudioContext time
   * @param windowEnd - End of window in AudioContext time
   * @param timeOffset - Offset: audioCtxTime = arrangementTime + timeOffset
   */
  scheduleWindow(
    lanes: readonly AutomationLane[],
    windowStart: number,
    windowEnd: number,
    timeOffset: number,
  ): void;

  /** Cancel all scheduled automation values */
  cancelAll(): void;
};

export function createAutomationScheduler(
  resolveParam: ParamResolver,
): AutomationScheduler {
  // Track params that have been scheduled for cancelAll
  const scheduledParams = new Set<ResolvedParam["param"]>();

  return {
    scheduleWindow(lanes, windowStart, windowEnd, timeOffset) {
      // Guard: zero-length window has nothing to schedule
      if (windowEnd <= windowStart) return;

      // Rebuild tracked params each window to avoid stale references
      const currentParams = new Set<ResolvedParam["param"]>();

      for (const lane of lanes) {
        // Only schedule in read/touch mode when armed
        if (!lane.armed) continue;
        if (lane.mode === "write") continue;
        if (lane.points.length === 0) continue;

        const resolved = resolveParam(lane);
        if (!resolved) continue;

        const { param, range } = resolved;
        currentParams.add(param);

        // Convert window to arrangement time
        const arrStart = windowStart - timeOffset;
        const arrEnd = windowEnd - timeOffset;

        // Cancel previous scheduling (prefer cancelAndHoldAtTime for glitch-free transitions)
        if (param.cancelAndHoldAtTime) {
          param.cancelAndHoldAtTime(windowStart);
        } else {
          param.cancelScheduledValues(windowStart);
        }

        // Schedule start value
        const startNorm = evaluateCurve(lane.points, arrStart);
        const startVal = denormalize(startNorm, range);
        param.setValueAtTime(startVal, windowStart);

        // Schedule exact breakpoints within the window for sample-accurate playback
        const innerPoints = findPointsInRange(lane.points, arrStart, arrEnd);
        for (const pt of innerPoints) {
          const ctxTime = pt.time + timeOffset;
          const val = denormalize(pt.value, range);
          param.linearRampToValueAtTime(val, ctxTime);
        }

        // Schedule end value
        const endNorm = evaluateCurve(lane.points, arrEnd);
        const endVal = denormalize(endNorm, range);
        param.linearRampToValueAtTime(endVal, windowEnd);
      }

      // Replace tracked params to avoid unbounded growth from stale references
      scheduledParams.clear();
      for (const p of currentParams) scheduledParams.add(p);
    },

    cancelAll() {
      for (const param of scheduledParams) {
        try {
          param.cancelScheduledValues(0);
        } catch {
          // Param may have been disconnected/disposed
        }
      }
      scheduledParams.clear();
    },
  };
}

