1	/**
2	 * Chorus/Flanger/Phaser effect using modulated delay.
3	 * DelayNode modulated by OscillatorNode LFO.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  {
11	    name: "Rate",
12	    key: "rate",
13	    min: 0.1,
14	    max: 10,
15	    default: 1.5,
16	    step: 0.1,
17	    unit: "Hz",
18	  },
19	  {
20	    name: "Depth",
21	    key: "depth",
22	    min: 0,
23	    max: 20,
24	    default: 5,
25	    step: 0.1,
26	    unit: "ms",
27	  },
28	  {
29	    name: "Mix",
30	    key: "mix",
31	    min: 0,
32	    max: 100,
33	    default: 50,
34	    step: 1,
35	    unit: "%",
36	  },
37	];
38	
39	export function createChorusFactory(): EffectFactory {
40	  return {
41	    definition: { id: "chorus", name: "Chorus", parameters: PARAMS },
42	    create(ctx, id) {
43	      let lfo: OscillatorNode;
44	      let lfoGain: GainNode;
45	      let delayNode: DelayNode;
46	
47	      return createBaseEffect({
48	        ctx,
49	        id,
50	        typeId: "chorus",
51	        params: PARAMS,
52	        buildChain(inputNode, outputNode) {
53	          delayNode = ctx.createDelay(0.05);
54	          delayNode.delayTime.value = 0.01;
55	
56	          lfo = ctx.createOscillator();
57	          lfo.type = "sine";
58	          lfo.frequency.value = 1.5;
59	
60	          lfoGain = ctx.createGain();
61	          lfoGain.gain.value = 0.005;
62	
63	          lfo.connect(lfoGain);
64	          lfoGain.connect(delayNode.delayTime as unknown as AudioParam);
65	
66	          inputNode.connect(delayNode);
67	          delayNode.connect(outputNode);
68	
69	          lfo.start();
70	        },
71	        disposeChain() {
72	          lfo.stop();
73	          lfo.disconnect();
74	          lfoGain.disconnect();
75	          delayNode.disconnect();
76	        },
77	        applyParam(key, value, setMix) {
78	          switch (key) {
79	            case "rate":
80	              lfo.frequency.value = value;
81	              break;
82	            case "depth":
83	              lfoGain.gain.value = value / 1000;
84	              break;
85	            case "mix":
86	              setMix(value / 100);
87	              break;
88	          }
89	        },
90	      });
91	    },
92	  };
93	}
