const lfo2Rate = Math.max(0.01, p.lfo2Rate + this.modAccGlobal.lfo2Rate);
const lfo1Val = this.lfo1.process(lfo1Rate, sr);
const lfo2Val = this.lfo2.process(lfo2Rate, sr);

