   const modPitchOsc2 = this.modAccGlobal.osc2Pitch + this.modAccVoice.osc2Pitch;

   // Pitch modulation (scaled to semitones, max +/-24)
   const pitchMod1 = modPitchOsc1 * 24;
   const pitchMod2 = modPitchOsc2 * 24;
