return undefined;
```

**What it does:**
```typescript
export function createParamResolver(
  mixer: MixerEngine,
  _effectsBridge: EffectsBridge,
): ParamResolver {
  return (lane: AutomationLane): ResolvedParam | undefined => {
    const { target, trackId } = lane;

    if (target.type === "mixer") {
      const strip = mixer.getStrip(trackId);
      if (!strip) return undefined;

      switch (target.param) {
        case "volume":
          return { param: strip.faderGain.gain, range: VOLUME_RANGE };
        case "pan":
          return { param: strip.panner.pan, range: PAN_RANGE };
      }
    }

    // ← THIS IS THE PROBLEM: Effect params always return undefined
    return undefined;
  };
}
```

**Why effect params return undefined:**
- `EffectInstance` only exposes `getParam()` and `setParam()` methods
- These are **not** AudioParams—they're custom functions
- AudioParams have `.setValueAtTime()` and `.linearRampToValueAtTime()` for sample-accurate scheduling
- The resolver needs a real AudioParam to schedule automation

