  filterEnv: 3,
  velocity: 4,
  aftertouch: 5,
  modWheel: 6,
  pitchBend: 7,
} as const;
```

**Destination indices** (lines 23-32):
```typescript
export const DEST_INDEX = {
  osc1Pitch: 0,
  osc2Pitch: 1,
  oscMix: 2,
  filterCutoff: 3,
  filterResonance: 4,
  ampLevel: 5,
  lfo1Rate: 6,
  lfo2Rate: 7,
} as const;
```

**Route application** (lines 88-102):
```typescript
export function applyModRoute(
  acc: ModAccumulators,
  sourceValues: Float64Array,
  sourceIdx: number,
  destIdx: number,
  amount: number,
  bipolar: boolean,
): void {
  const raw = sourceValues[sourceIdx] ?? 0;
  const value = bipolar ? raw : (raw + 1) / 2;  // Unipolar: map [-1,1] to [0,1]
  const key = DEST_KEYS[destIdx];
  if (key !== undefined) {
    acc[key] += value * amount;  // Accumulate modulation offset
  }
}
```

---

### **Summary: Key Differences**

| Aspect | synth-renderer.ts | synth-processor.ts |
|--------|-------------------|-------------------|
| **LFO Creation** | Created but discarded (line 111) | Created in constructor (line 127-128) |
| **LFO Processing** | Never called | Called every sample (line 306-307) |
| **Pitch Modulation** | Not implemented | Lines 405-424 |
| **Filter Modulation** | Envelope only (line 187-189) | Envelope + LFO (line 441-442) |
| **Amplitude Modulation** | Not implemented | Lines 465-466 |
| **Modulation System** | Missing entirely | Full pre-allocated matrix |
| **Allocation Pattern** | Per-frame allocations OK | Zero-allocation in process() |

---

### **Critical Issues**

1. **Bounce renderer LFOs are dead code** → Need to implement modulation matrix same as SynthProcessor
2. **Effect parameters not AudioParams** → Automation always returns undefined for effects
3. **Automation scheduler expects AudioParams** → Cannot work with custom setParam() functions
4. **synth-renderer lacks modAccumulators** → Must add ModAccumulators and route application logic

This is the exact mismatch causing your bounce/automation issues.

