1	/**
2	 * Modulation engine: pure, zero-allocation functions for computing
3	 * modulation offsets from routes. Used inside the AudioWorklet processor.
4	 *
5	 * Design: Pre-allocated accumulators are reset each quantum, then
6	 * each active route adds source * amount to its destination accumulator.
7	 * The processor reads accumulators to offset synth parameters.
8	 */
9	
10	// ─── Source and destination index maps (numeric for worklet) ───
11	
12	export const SOURCE_INDEX = {
13	  lfo1: 0,
14	  lfo2: 1,
15	  ampEnv: 2,
16	  filterEnv: 3,
17	  velocity: 4,
18	  aftertouch: 5,
19	  modWheel: 6,
20	  pitchBend: 7,
21	} as const;
22	
23	export const DEST_INDEX = {
24	  osc1Pitch: 0,
25	  osc2Pitch: 1,
26	  oscMix: 2,
27	  filterCutoff: 3,
28	  filterResonance: 4,
29	  ampLevel: 5,
30	  lfo1Rate: 6,
31	  lfo2Rate: 7,
32	} as const;
33	
34	// ─── Accumulators ───
35	
