37	  osc1Pitch: number;
38	  osc2Pitch: number;
39	  oscMix: number;
40	  filterCutoff: number;
41	  filterResonance: number;
42	  ampLevel: number;
43	  lfo1Rate: number;
44	  lfo2Rate: number;
45	};
46	
47	export function createModAccumulators(): ModAccumulators {
48	  return {
49	    osc1Pitch: 0,
50	    osc2Pitch: 0,
51	    oscMix: 0,
52	    filterCutoff: 0,
53	    filterResonance: 0,
54	    ampLevel: 0,
55	    lfo1Rate: 0,
56	    lfo2Rate: 0,
57	  };
58	}
59	
60	export function resetAccumulators(acc: ModAccumulators): void {
61	  acc.osc1Pitch = 0;
62	  acc.osc2Pitch = 0;
63	  acc.oscMix = 0;
64	  acc.filterCutoff = 0;
65	  acc.filterResonance = 0;
66	  acc.ampLevel = 0;
67	  acc.lfo1Rate = 0;
68	  acc.lfo2Rate = 0;
69	}
70	
71	// Dest keys indexed by DEST_INDEX values for fast lookup
72	const DEST_KEYS: readonly (keyof ModAccumulators)[] = [
73	  "osc1Pitch",
74	  "osc2Pitch",
75	  "oscMix",
76	  "filterCutoff",
77	  "filterResonance",
78	  "ampLevel",
79	  "lfo1Rate",
80	  "lfo2Rate",
81	];
