84	 * Apply a single modulation route to accumulators.
85	 * Zero-allocation: reads from pre-allocated sourceValues array,
86	 * writes to pre-allocated accumulators object.
87	 */
88	export function applyModRoute(
89	  acc: ModAccumulators,
90	  sourceValues: Float64Array,
91	  sourceIdx: number,
92	  destIdx: number,
93	  amount: number,
94	  bipolar: boolean,
95	): void {
96	  const raw = sourceValues[sourceIdx] ?? 0;
97	  const value = bipolar ? raw : (raw + 1) / 2;
98	  const key = DEST_KEYS[destIdx];
