export type {
  EffectParameterSchema,
  EffectDefinition,
  EffectInstance,
  EffectPreset,
  EffectFactory,
  EffectRegistry,
} from "./types";

export { createEffectRegistry } from "./registry";
export { createBaseEffect } from "./create-effect";
export { effectPresetSchema, validatePreset } from "./preset-schema";
export { createDefaultRegistry } from "./default-registry";
export { createEffectsBridge } from "./effects-bridge";
export type { EffectsBridge } from "./effects-bridge";
export {
  EffectsBridgeProvider,
  useEffectsBridgeContext,
} from "./EffectsBridgeProvider";

export { createReverbFactory } from "./reverb";
export { createDelayFactory } from "./delay";
export { createCompressorFactory } from "./compressor";
export { createEqFactory } from "./eq";
export { createDistortionFactory } from "./distortion";
export { createChorusFactory } from "./chorus";
export { createFreeverbFactory } from "./freeverb";

/**
 * Synthesizer AudioWorklet processor.
 * Runs on the audio rendering thread — zero allocations in process().
 *
 * Architecture: 16 fixed voices, each with:
 * - 2 PolyBLEP oscillators
 * - Biquad filter (LP/HP/BP)
 * - ADSR amplitude envelope
 * - ADSR filter envelope
 * Shared: 2 LFOs, hardwired modulation matrix.
 *
 * INV-3/NFR-14: Zero-allocation process().
 * MIT-H4-5: Oldest-steal with 5ms crossfade.
 * MIT-H4-6: 2ms minimum release time.
 * R-STA-05: Legato mode with pitch glide.
 */

import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
import {
  createADSREnvelope,
  type ADSREnvelope,
  type ADSRParams,
} from "./dsp/adsr";
import {
  computeBiquadCoeffs,
  createBiquadFilter,
