  voices: OfflineVoice[],
  note: number,
  velocity: number,
  params: SynthParameterMap,
  sampleRate: number,
): void {
  // Find free voice
  let idx = -1;
  for (let i = 0; i < MAX_VOICES; i++) {
    if (voices[i]?.active !== true) {
      idx = i;
      break;
    }
  }

  // Steal oldest releasing voice if no free voice
  if (idx === -1) {
    for (let i = 0; i < MAX_VOICES; i++) {
      if (voices[i]?.releasing === true) {
        idx = i;
        break;
      }
    }
  }

  // Steal first voice as last resort
  if (idx === -1) idx = 0;

  const v = voices[idx];
  if (!v) return;

  const freq = midiToFreq(note);
  v.active = true;
  v.releasing = false;
  v.note = note;
  v.velocity = velocity / 127;
  v.targetFreq = freq;
  v.currentFreq = freq;

  v.osc1.reset();
  v.osc2.reset();
  v.filter.reset();
  v.osc1.type = params.osc1Type;
  v.osc2.type = params.osc2Type;
  v.filter.type = params.filterType;

