/** Release all voices playing this note */
function releaseNote(voices: OfflineVoice[], note: number): void {
  for (let i = 0; i < MAX_VOICES; i++) {
    const v = voices[i];
    if (v && v.active && !v.releasing && v.note === note) {
      v.releasing = true;
