  computeBiquadCoeffs(
    params.filterType,
    Math.min(Math.max(params.filterCutoff, 20), sampleRate / 2 - 100),
    params.filterResonance,
    sampleRate,
    v.filter.coeffs,
  );

  v.ampEnv.gate(false);
  v.filterEnv.gate(false);
}

